# Module providing mathematical utility functions and constants

class MathConstants:
    PI: float = 3.14159
    E: float = 2.71828

    @staticmethod
    def get_golden_ratio() -> float:
        return 1.618

class Calculator:
    history: list[int]

    def __init__(self):
        self.history = []

    def add_to_history(self, value: int) -> None:
        self.history.append(value)

    def get_history_sum(self) -> int:
        total: int = 0
        for val in self.history:
            total += val
        return total

def factorial(n: int) -> int:
    if n <= 1:
        return 1
    result: int = 1
    i: int = 2
    while i <= n:
        result *= i
        i += 1
    return result

def power(base: int, exp: int) -> int:
    result: int = 1
    i: int = 0
    while i < exp:
        result *= base
        i += 1
    return result

