# Module providing string manipulation utilities

from math_utils import MathConstants

class TextFormatter:
    prefix: str

    def __init__(self, prefix: str):
        self.prefix = prefix

    def format_message(self, msg: str) -> str:
        return f"{self.prefix}: {msg}"

def repeat_string(text: str, count: int) -> str:
    result: str = ""
    i: int = 0
    while i < count:
        result += text
        i += 1
    return result

def get_math_constant_info() -> str:
    pi_str: str = f"PI is approximately {MathConstants.PI}"
    return pi_str
